def main():
    board = init_checkers_board()

    current_player = 'B'
    while True:
        print(f"Current Player: {current_player}")
        print_board(board)

        from_pos = input("Enter the from position (e.g., A1): ")
        to_pos = input("Enter the to position (e.g., B2): ")

        if is_valid_move(board, from_pos, to_pos):
            make_move(board, from_pos, to_pos)

            if not has_valid_moves(board, 'W' if current_player == 'B' else 'B'):
                print(f"Player {current_player} wins!")
                break

            current_player = 'W' if current_player == 'B' else 'B'
        else:
            print("Invalid move. Please try again.")

if __name__ == "__main__":
    main()
